import { useFormik } from "formik";
import { LeagueTable } from "../../objects/league-table";
import { PostLeagueTableResult } from "../../services/league-table-service";

const AdminResult = ()  =>
{
    const formik = useFormik({
        initialValues :{
                homeTeam: 0,                 
                season: 6,
                },
        onSubmit : values => {
            const leageTable : LeagueTable = {
                id : 1,
                achieveablePoints: 0,
                drawn : 0,
                gd : 0,
                glsA : 5,
                glsFor: 6,
                lost : 0,
                pld : 0,
                points : 0,
                seasonId : values.season,
                teamId : values.homeTeam,
                teamName : "Tigers",
                won : 1
            }
            PostLeagueTableResult(leageTable);
        }
    });

    return(

        <>
        <div>hi</div>
        <div>           
            <form onSubmit={formik.handleSubmit} >
                 <input type="text" {...formik.getFieldProps("homeTeam")}/> 
                 <input type="text" {...formik.getFieldProps("awayTeam")}/> 
                 <input type="text" {...formik.getFieldProps("season")}/> 
                 <button type="submit">Go</button>  
            </form>            
        </div>
        </>
    );
}

export default AdminResult;
